<?php
namespace App\Domain\Repayments\Actions;
use App\Enums\InstallmentStatus;use App\Enums\LoanStatus;use App\Models\Loan;use App\Models\LoanRecoveryCase;use App\Models\LoanRepaymentInstallment;use Illuminate\Support\Str;
class RefreshLoanArrears{public function execute():array{$installmentsUpdated=0;$casesOpened=0;LoanRepaymentInstallment::query()->with('loan.product')->whereNotIn('status',[InstallmentStatus::Paid->value,InstallmentStatus::Waived->value,InstallmentStatus::Rescheduled->value])->whereDate('due_date','<',today())->chunkById(200,function($installments)use(&$installmentsUpdated,&$casesOpened){foreach($installments as $installment){$total=$installment->principal_due_minor+$installment->interest_due_minor+$installment->charges_due_minor+$installment->penalties_due_minor+$installment->recovery_expenses_due_minor;if($installment->amount_paid_minor<$total){$installment->update(['status'=>InstallmentStatus::Overdue,'overdue_since'=>$installment->overdue_since??$installment->due_date]);$installment->loan->update(['status'=>LoanStatus::InArrears]);$installmentsUpdated++;$days=(int)$installment->due_date->diffInDays(today());$threshold=(int)($installment->loan->product->configuration['recovery_escalation_days']??30);if($days>=$threshold){$arrears=$installment->loan->installments()->where('status',InstallmentStatus::Overdue->value)->get()->sum(fn($row)=>$row->principal_due_minor+$row->interest_due_minor+$row->charges_due_minor+$row->penalties_due_minor+$row->recovery_expenses_due_minor-$row->amount_paid_minor);$case=LoanRecoveryCase::query()->firstOrCreate(['loan_id'=>$installment->loan_id],['member_id'=>$installment->loan->member_id,'reference'=>'REC-'.strtoupper(Str::ulid()),'days_past_due'=>$days,'arrears_minor'=>$arrears,'opened_at'=>now()]);if($case->wasRecentlyCreated)$casesOpened++;else $case->update(['days_past_due'=>$days,'arrears_minor'=>$arrears]);}}}});return ['installments_updated'=>$installmentsUpdated,'recovery_cases_opened'=>$casesOpened];}}
